const items = $input.all();

const KNOWN_SKILLS = [
  'python', 'machine learning', 'sql', 'javascript', 'typescript', 'react',
  'node.js', 'node', 'mongodb', 'express', 'java', 'c++', 'aws', 'docker',
  'kubernetes', 'pandas', 'numpy', 'tensorflow', 'pytorch', 'power bi', 'excel'
];

function toTitleCase(text) {
  return text
    .toLowerCase()
    .split(/\s+/)
    .map((w) => w.charAt(0).toUpperCase() + w.slice(1))
    .join(' ');
}

return items.map((item) => {
  // Extract From PDF may not forward binary; fetch original uploaded binary from Webhook item.
  const webhookItem = $items('Webhook', 0, 0)[0] || {};
  const bin = item.binary?.file || webhookItem.binary?.file;

  if (!bin?.data) {
    throw new Error('Missing PDF file in multipart/form-data. Expected field name file.');
  }

  const extracted = String(item.json?.text || '').trim();
  const cleaned = extracted
    .replace(/\r\n/g, '\n')
    .replace(/\t/g, ' ')
    .replace(/[ ]{2,}/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();

  if (!cleaned) {
    throw new Error('Unable to extract readable text from PDF.');
  }

  const resumeText = cleaned;
  const emailMatch = resumeText.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
  const heuristicEmail = emailMatch ? emailMatch[0].toLowerCase() : '';

  let heuristicName = '';
  const nameLabelMatch = resumeText.match(/(?:^|\n)\s*name\s*[:\-]\s*([^\n]+)/i);
  if (nameLabelMatch?.[1]) {
    heuristicName = nameLabelMatch[1].trim();
  } else {
    const firstLine = resumeText.split('\n').map((l) => l.trim()).find(Boolean) || '';
    if (/^[A-Za-z][A-Za-z .'-]{2,}$/.test(firstLine) && !/@/.test(firstLine)) {
      heuristicName = firstLine;
    }
  }

  const lower = resumeText.toLowerCase();
  const heuristicSkills = KNOWN_SKILLS
    .filter((s) => lower.includes(s))
    .map((s) => toTitleCase(s));

  item.json = {
    ...item.json,
    fileName: bin.fileName || 'resume.pdf',
    mimeType: bin.mimeType || 'application/pdf',
    resumeText,
    heuristicName: heuristicName || 'Unknown',
    heuristicEmail: heuristicEmail || 'unknown@example.com',
    heuristicSkills: [...new Set(heuristicSkills)]
  };

  item.binary = {
    ...(item.binary || {}),
    file: bin
  };

  return item;
});

const raw = $json?.response || '';
const cleaned = String(raw)
  .replace(/```json/gi, '')
  .replace(/```/g, '')
  .trim();

let parsed = {};
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  const start = cleaned.indexOf('{');
  const end = cleaned.lastIndexOf('}');
  if (start !== -1 && end !== -1 && end > start) {
    parsed = JSON.parse(cleaned.slice(start, end + 1));
  }
}

const baseItem = $items('Extract and Clean Resume Text', 0, 0)[0] || {};
const base = baseItem.json || {};
const fileBinary = baseItem.binary?.file ? { file: baseItem.binary.file } : undefined;

const finalName = String(parsed.name || '').trim() || base.heuristicName || 'Unknown';
const finalEmail = String(parsed.email || '').trim().toLowerCase() || base.heuristicEmail || 'unknown@example.com';
const finalSkills = Array.isArray(parsed.skills) && parsed.skills.length
  ? parsed.skills.map((s) => String(s).trim()).filter(Boolean)
  : (Array.isArray(base.heuristicSkills) ? base.heuristicSkills : []);

return [
  {
    json: {
      name: finalName,
      email: finalEmail,
      skills: finalSkills,
      experience: Number(parsed.experience) || 0,
      education: parsed.education || ''
    },
    binary: fileBinary
  }
];

