const inputItem = $input.first() || {};
const rawScore = $json?.response || '';
const cleanedScore = String(rawScore)
  .replace(/```json/gi, '')
  .replace(/```/g, '')
  .trim();

let scoreObj = {};
try {
  scoreObj = JSON.parse(cleanedScore);
} catch (e) {
  const start = cleanedScore.indexOf('{');
  const end = cleanedScore.lastIndexOf('}');
  if (start !== -1 && end !== -1 && end > start) {
    scoreObj = JSON.parse(cleanedScore.slice(start, end + 1));
  }
}

const candidateName = String($json.name || '').trim() || 'Unknown Candidate';
const candidateEmail = $json.email || '';
const candidateSkills = Array.isArray($json.skills) ? $json.skills : [];
const experience = Number($json.experience) || 0;
const education = $json.education || '';

const mustHaveSkills = ['python', 'machine learning', 'sql'];
const normalizedSkills = candidateSkills.map((s) => String(s).toLowerCase().trim());
const matchedMustHaveSkills = mustHaveSkills.filter((s) => normalizedSkills.some((x) => x.includes(s)));
const missingMustHaveSkills = mustHaveSkills.filter((s) => !matchedMustHaveSkills.includes(s));

const hasMinimumExperience = experience >= 2;
const modelScore = Math.max(0, Math.min(100, Number(scoreObj.score) || 0));

const skillScore = Math.round((matchedMustHaveSkills.length / mustHaveSkills.length) * 60);
const experienceScore = hasMinimumExperience ? 20 : Math.max(0, Math.round((experience / 2) * 20));
const finalScore = Math.max(0, Math.min(100, Math.round(skillScore + experienceScore + (modelScore * 0.2))));

const shortlisted = matchedMustHaveSkills.length >= 2 && hasMinimumExperience && finalScore >= 70;
const status = shortlisted ? 'Shortlisted' : 'Rejected';
const fileBinary = inputItem.binary?.file ? { file: inputItem.binary.file } : undefined;

const modelMissingSkills = Array.isArray(scoreObj.missing_skills) ? scoreObj.missing_skills : [];
const combinedMissingSkills = [...new Set([...missingMustHaveSkills, ...modelMissingSkills.map((s) => String(s).toLowerCase())])];

return [
  {
    json: {
      name: candidateName,
      email: candidateEmail,
      skills: candidateSkills,
      experience,
      education,
      score: finalScore,
      decision: shortlisted ? 'Shortlist' : 'Reject',
      missing_skills: combinedMissingSkills,
      strengths: Array.isArray(scoreObj.strengths) ? scoreObj.strengths : [],
      status
    },
    binary: fileBinary
  }
];

